import { buildMatchFn } from "../../_lib/buildMatchFn.mjs";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.mjs";

const matchOrdinalNumberPattern =
  /^(\d+)(-?(械|褟|谐邪|褨|褘|邪械|邪褟|褟褟|褕褘|谐褨|褑褨|褌褘|屑褘))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((写邪 )?薪\.?\s?褝\.?)/i,
  abbreviated: /^((写邪 )?薪\.?\s?褝\.?)/i,
  wide: /^(写邪 薪邪褕邪泄 褝褉褘|薪邪褕邪泄 褝褉褘|薪邪褕邪 褝褉邪)/i,
};
const parseEraPatterns = {
  any: [/^写/i, /^薪/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[褘褨]?)? 泻胁.?/i,
  wide: /^[1234](-?[褘褨]?)? 泻胁邪褉褌邪谢/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[褋谢泻屑褔卸胁]/i,
  abbreviated:
    /^(褋褌褍写蟹|谢褞褌|褋邪泻|泻褉邪褋|屑邪[泄褟]|褔褝褉胁|谢褨锌|卸薪|胁械褉|泻邪褋褌褉|谢褨褋褌|褋薪械卸)\.?/i,
  wide: /^(褋褌褍写蟹械薪[褜褟]|谢褞褌(褘|邪谐邪)|褋邪泻邪胁褨泻邪?|泻褉邪褋邪胁褨泻邪?|屑邪[泄褟]|褔褝褉胁械薪[褜褟]|谢褨锌械薪[褜褟]|卸薪褨(胁械薪褜|褳薪褟)|胁械褉邪褋(械薪褜|薪褟)|泻邪褋褌褉褘褔薪褨泻邪?|谢褨褋褌邪锌邪写邪?|褋薪械卸(邪薪褜|薪褟))/i,
};
const parseMonthPatterns = {
  narrow: [
    /^褋/i,
    /^谢/i,
    /^褋/i,
    /^泻/i,
    /^屑/i,
    /^褔/i,
    /^谢/i,
    /^卸/i,
    /^胁/i,
    /^泻/i,
    /^谢/i,
    /^褋/i,
  ],

  any: [
    /^褋褌/i,
    /^谢褞/i,
    /^褋邪/i,
    /^泻褉/i,
    /^屑邪/i,
    /^褔/i,
    /^谢褨锌/i,
    /^卸/i,
    /^胁/i,
    /^泻邪/i,
    /^谢褨褋/i,
    /^褋薪/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[薪锌邪褋褔]/i,
  short: /^(薪写|薪褟|锌薪|锌邪|邪褳|邪褌|褋褉|褋械|褔褑|褔邪|锌褌|锌褟|褋斜|褋褍)\.?/i,
  abbreviated: /^(薪褟写蟹?|薪写蟹|锌薪写|锌邪薪|邪褳褌|褋褉写|褋械褉|褔褑胁|褔邪褑|锌褌薪|锌褟褌|褋褍斜).?/i,
  wide: /^(薪褟写蟹械谢[褟褨]|锌邪薪褟写蟹械谢(邪泻|泻邪)|邪褳褌芯褉(邪泻|泻邪)|褋械褉邪写[邪褘]|褔邪褑胁(械褉|褟褉谐邪)|锌褟褌薪褨褑[邪褘]|褋褍斜芯褌[邪褘])/i,
};
const parseDayPatterns = {
  narrow: [/^薪/i, /^锌/i, /^邪/i, /^褋/i, /^褔/i, /^锌/i, /^褋/i],
  any: [/^薪/i, /^锌[邪薪]/i, /^邪/i, /^褋[械褉]/i, /^褔/i, /^锌[褟褌]/i, /^褋[褍斜]/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([写锌]锌|锌芯褳薪\.?|锌芯褳写\.?|褉邪薪\.?|写蟹械薪褜|写薪褟|胁械褔\.?|薪芯褔褘?)/i,
  abbreviated: /^([写锌]锌|锌芯褳薪\.?|锌芯褳写\.?|褉邪薪\.?|写蟹械薪褜|写薪褟|胁械褔\.?|薪芯褔褘?)/i,
  wide: /^([写锌]锌|锌芯褳薪邪褔|锌芯褳写蟹械薪褜|褉邪薪褨褑[邪褘]|写蟹械薪褜|写薪褟|胁械褔邪褉邪?|薪芯褔褘?)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^写锌/i,
    pm: /^锌锌/i,
    midnight: /^锌芯褳薪/i,
    noon: /^锌芯褳写/i,
    morning: /^褉/i,
    afternoon: /^写[蟹薪]/i,
    evening: /^胁/i,
    night: /^薪/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
